6685 InstCombiner::getFlippedStrictnessPredicateAndConstant(CmpInst::Predicate Pred,
6686                                                        Constant *C) {
6687   assert(ICmpInst::isRelational(Pred) && ICmpInst::isIntPredicate(Pred) &&
6688          "Only for relational integer predicates.");
6689 
6690   Type *Type = C->getType();
6691   bool IsSigned = ICmpInst::isSigned(Pred);
6692 
6693   CmpInst::Predicate UnsignedPred = ICmpInst::getUnsignedPredicate(Pred);
6694   bool WillIncrement =
6695       UnsignedPred == ICmpInst::ICMP_ULE || UnsignedPred == ICmpInst::ICMP_UGT;
6696 
6697   // Check if the constant operand can be safely incremented/decremented
6698   // without overflowing/underflowing.
6699   auto ConstantIsOk = [WillIncrement, IsSigned](ConstantInt *C) {
6700     return WillIncrement ? !C->isMaxValue(IsSigned) : !C->isMinValue(IsSigned);
6701   };
6702 
6703   Constant *SafeReplacementConstant = nullptr;
6704   if (auto *CI = dyn_cast<ConstantInt>(C)) {
6705     // Bail out if the constant can't be safely incremented/decremented.
6706     if (!ConstantIsOk(CI))
6707       return std::nullopt;
6708   } else if (auto *FVTy = dyn_cast<FixedVectorType>(Type)) {
6709     unsigned NumElts = FVTy->getNumElements();
6710     for (unsigned i = 0; i != NumElts; ++i) {
6711       Constant *Elt = C->getAggregateElement(i);
6712       if (!Elt)
6713         return std::nullopt;
6714 
6715       if (isa<UndefValue>(Elt))
6716         continue;
6717 
6718       // Bail out if we can't determine if this constant is min/max or if we
6719       // know that this constant is min/max.
6720       auto *CI = dyn_cast<ConstantInt>(Elt);
6721       if (!CI || !ConstantIsOk(CI))
6722         return std::nullopt;
6723 
6724       if (!SafeReplacementConstant)
6725         SafeReplacementConstant = CI;
6726     }
6727   } else if (isa<VectorType>(C->getType())) {
6728     // Handle scalable splat
6729     Value *SplatC = C->getSplatValue();
6730     auto *CI = dyn_cast_or_null<ConstantInt>(SplatC);
6731     // Bail out if the constant can't be safely incremented/decremented.
6732     if (!CI || !ConstantIsOk(CI))
6733       return std::nullopt;
6734   } else {
6735     // ConstantExpr?
6736     return std::nullopt;
6737   }
6738 
6739   // It may not be safe to change a compare predicate in the presence of
6740   // undefined elements, so replace those elements with the first safe constant
6741   // that we found.
6742   // TODO: in case of poison, it is safe; let's replace undefs only.
6743   if (C->containsUndefOrPoisonElement()) {
6744     assert(SafeReplacementConstant && "Replacement constant not set");
6745     C = Constant::replaceUndefsWith(C, SafeReplacementConstant);
6746   }
6747 
6748   CmpInst::Predicate NewPred = CmpInst::getFlippedStrictnessPredicate(Pred);
6749 
6750   // Increment or decrement the constant.
6751   Constant *OneOrNegOne = ConstantInt::get(Type, WillIncrement ? 1 : -1, true);
6752   Constant *NewC = ConstantExpr::getAdd(C, OneOrNegOne);
6753 
6754   return std::make_pair(NewPred, NewC);
6755 }
